Ah, mon ami! In the world of C++, starting a new process with file descriptors connected to its input and output is almost as fun as a day at the arcade with a digestive! Here’s how you can do it with a bit of French flair:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Créons un tuyau!
    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur lors de la création du tuyau!" << std::endl;
        return 1;
    }

    // Lancement de notre tout nouveau processus!
    pid = fork();

    if (pid < 0) {
        std::cerr << "Erreur lors du fork!" << std::endl;
        return 1;
    } else if (pid > 0) { // Parent process
        close(pipefd[0]); // Ferme la lecture du tuyau
        std::cout << "Le processus parent a lancé le processus enfant. Maintenant, ils sont connectés par le tuyau!" << std::endl;
    } else { // Child process
        close(pipefd[1]); // Ferme l'écriture du tuyau
        dup2(pipefd[0], STDIN_FILENO); // Connecte le fichier d'entrée au tuyau
        dup2(pipefd[0], STDOUT_FILENO); // Connecte le fichier de sortie au tuyau
        close(pipefd[0]); // Ferme le tuyau
        execlp("ls", "ls", NULL); // Lance un processus ls
    }

    wait(NULL); // Attends que le processus enfant termine

    return 0;
}
```

Voilà! Vous pouvez maintenant jouer avec vos processus en France, comme un vrai professional!
